13	// LoadDir reads all *.yaml and *.yml files in dir as Check definitions.
14	// If dir does not exist, returns (nil, nil) — projects without a checks
15	// directory have no checks. Any unreadable file, malformed YAML, or
16	// unknown field is reported with the source file and (when available)
17	// line:column.
18	func LoadDir(dir string) ([]Check, error) {
19		entries, err := os.ReadDir(dir)
20		if err != nil {
21			if os.IsNotExist(err) {
22				return nil, nil
23			}
24			return nil, fmt.Errorf("checks: read dir %s: %w", dir, err)
25		}
26	
27		var paths []string
28		for _, e := range entries {
29			if e.IsDir() {
30				continue
31			}
32			ext := filepath.Ext(e.Name())
33			if ext != ".yaml" && ext != ".yml" {
34				continue
35			}
36			paths = append(paths, filepath.Join(dir, e.Name()))
37		}
38		sort.Strings(paths)
39	
40		out := make([]Check, 0, len(paths))
41		seen := make(map[string]string, len(paths))
42		for _, p := range paths {
43			c, err := LoadFile(p)
44			if err != nil {
45				return nil, err
46			}
47			if prior, dup := seen[c.Name]; dup {
48				return nil, fmt.Errorf("checks: duplicate check name %q in %s (also defined in %s)", c.Name, p, prior)
49			}
50			seen[c.Name] = p
51			out = append(out, c)
52		}
53		return out, nil
54	}
55	
56	// LoadFile parses a single check definition file. Unknown fields and
57	// malformed YAML are reported with file:line context.
58	func LoadFile(path string) (Check, error) {
59		data, err := os.ReadFile(path)
60		if err != nil {
61			return Check{}, fmt.Errorf("checks: read %s: %w", path, err)
62		}
63		dec := yaml.NewDecoder(bytes.NewReader(data))
64		dec.KnownFields(true)
65		var c Check
66		if err := dec.Decode(&c); err != nil {
67			return Check{}, fmt.Errorf("checks: parse %s: %w", path, err)
68		}
69		c.SourceFile = path
70		if err := c.Validate(); err != nil {
71			return Check{}, fmt.Errorf("checks: %s: %w", path, err)
72		}
73		return c, nil
74	}
75	
76	// Validate enforces required-field rules on a parsed check.
77	func (c *Check) Validate() error {
78		if c.Name == "" {
79			return fmt.Errorf("missing required field: name")
80		}
81		if c.Command == "" {
82			return fmt.Errorf("missing required field: command")
83		}
84		if c.When == "" {
85			return fmt.Errorf("missing required field: when")
86		}
87		if c.When != HookPreMerge {
88			return fmt.Errorf("unsupported hook %q (only %q is supported)", c.When, HookPreMerge)
89		}
90		return nil
91	}
92	
93	// Applies reports whether the check should run for the given context.
94	func (c *Check) Applies(ctx InvocationContext) bool {
95		a := c.AppliesTo
96		if len(a.Paths) == 0 && len(a.Labels) == 0 {
97			return true
98		}
99		for _, lbl := range a.Labels {
100			for _, b := range ctx.BeadLabels {
101				if lbl == b {
102					return true
103				}
104			}
105		}
106		for _, glob := range a.Paths {
107			for _, p := range ctx.ChangedPaths {
108				if matched, _ := filepath.Match(glob, p); matched {
109					return true
110				}
111				// Also try matching against just the basename so
112				// patterns like "*.go" match deeply nested files.
113				if matched, _ := filepath.Match(glob, filepath.Base(p)); matched {
114					return true
115				}
116			}
117		}
118		return false
119	}
